            const { execSync } = require('child_process');
            const fs = require('fs');
            const sqlite3 = require('sqlite3').verbose();

            try {
              // 1. Install deps (open-source only)
              console.log('📦 Installing open-source dependencies...');
              execSync('npm install && npm audit fix',{stdio:'inherit'});

              // 2. Ensure dirs
              ['assets','android/app/src/main/res','pwa/public'].forEach(d=>{
                if(!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
              });

              // 3. Init DB (SQLite zero-cost)
              console.log('🗄️ Initializing SQLite...');
              const db = new sqlite3.Database('app.db');
              db.serialize(()=>{ db.run('CREATE TABLE IF NOT EXISTS plantations(id INTEGER PRIMARY KEY, name TEXT, date TEXT)'); });
              db.close();

              // 4. OAuth config (Auth.js / Keycloak)
              fs.writeFileSync('auth.config.json', JSON.stringify({
                provider: 'authjs',
                free: true,
                oauth: ['google','github','email']
              },null,2));
              console.log('🔑 OAuth config generated.');

              // 5. Auto-fix
              try { execSync('npm run lint --fix',{stdio:'inherit'}); } catch(e){ console.log('⚠️ Lint skipped.'); }

              // 6. Build auto-select
              let buildType = '';
              if(fs.existsSync('android/gradlew')){
                console.log('📱 Android project detected. Building APK...');
                execSync('./gradlew assembleRelease',{stdio:'inherit'});
                buildType = 'APK';
              } else if(fs.existsSync('pwa/package.json')){
                console.log('🌐 PWA project detected. Building web app...');
                execSync('npm run build && npm run export',{stdio:'inherit'});
                buildType = 'PWA';
              }

              // 7. Meta-share
              const link = 'https://your-vercel-deployment-link.com/app-release.apk';
              const meta = `
                <html><head>
                <meta property='og:title' content='Plantation Tracker'>
                <meta property='og:description' content='Open-source, zero-cost plantation tracking app.'>
                <meta property='og:image' content='https://your-vercel-deployment-link.com/icon.png'>
                <meta property='og:url' content='${link}'>
                <meta name='twitter:card' content='summary_large_image'>
                </head><body><a href='${link}'>Download ${buildType}</a></body></html>`;
              fs.writeFileSync('meta.html',meta);

              // 8. Deploy (Vercel free tier)
              const deployOutput = execSync('npx vercel --prod --yes').toString();
              const match = deployOutput.match(/https?:\/\/[^\s]+/);
              const finalLink = match ? match[0] : link;
              console.log(`✅ Deployment complete. Final ${buildType} link: ${finalLink}`);

              // 9. Update docs
              const docs = `
# Plantation Tracker (Open-Source)

## Build Outputs
- ${buildType}: ${finalLink}

## Pipeline
- Dependencies auto-installed (open-source only)
- Assets auto-generated
- SQLite DB initialized
- OAuth config (Auth.js/Keycloak)
- Auto-fix applied
- Build complete
- Deployment live
- Meta tags generated

_Last updated: ${new Date().toISOString()}_
`;
              fs.writeFileSync('README.md', docs);
              console.log('📖 Documentation updated.');

              // 10. Auto-commit docs to GitHub
              execSync('git add README.md meta.html auth.config.json && git commit -m "docs: auto-update" && git push',{stdio:'inherit'});
              console.log('✅ Docs pushed to GitHub.');

              // 11. Self-improve
              console.log('🔍 Self-improvement: Using SQLite/Postgres, Auth.js, ESLint, Vercel free tier.');
            } catch(err){
              console.error('❌ Pipeline failed:',err);
            }
